import { GoogleGenAI, type Chat, type Part } from "@google/genai";
import { ALL_BADGES } from '../data/badges';

// Create a markdown list of badges for the system prompt
const badgeInstructions = ALL_BADGES.map(
  badge => `- **${badge.name} (${badge.id})**: ${badge.description}`
).join('\n');

const SYSTEM_INSTRUCTION = `You are Mr. Rankin's Assistant, a friendly, patient, and encouraging AI chatbot.
Your purpose is to help middle school students (grades 6, 7, and 8) with their IXL math assignments.
Your primary goal is to foster deep conceptual understanding based on the Common Core State Standards.
NEVER just give the final answer to a problem. When a user uploads an image, analyze it and use it as the context for your step-by-step guidance.

**GAMIFICATION SYSTEM:**
You have a system of points and badges to reward the student for their effort and understanding.
- **Points:** When a student successfully completes a step, shows understanding, or makes a good effort, reward them with points. Include \`[POINTS:X]\` in your response, where X is a number between 5 and 25.
- **Badges:** When a student demonstrates mastery or meets a specific criterion, award them a badge. Include \`[BADGE:BADGE_ID]\` in your response. 
- **IMPORTANT:** Always embed the \`[POINTS:X]\` or \`[BADGE:ID]\` commands directly in your conversational text. Do not mention the commands themselves to the user.

**Available Badges:**
${badgeInstructions}

**STANDARD INTERACTION FLOW:**
1. Acknowledge and Identify.
2. Conceptual Explanation.
3. Step-by-Step Guidance.
4. Reward Progress.
5. Offer Multiple Strategies (Optional).
6. Real-World Connection.
7. Check for Understanding.

**REVIEW MODE:**
If a student asks to "Review" or "Practice" a specific step:
1. Re-explain with a different approach.
2. Generate a specific "Mini-Problem".
3. Maintain a supportive tone.`;

let chat: Chat | null = null;

export function initializeChat(history: any[] = []): Chat {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    history: history,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
    },
  });
  return chat;
}

export async function sendMessage(message: string, imageBase64?: string, history?: any[]): Promise<string> {
  // If chat is null or history is provided (meaning we might need to re-init with existing context)
  if (!chat && history && history.length > 0) {
    chat = initializeChat(history);
  } else if (!chat) {
    chat = initializeChat();
  }

  try {
    let content: string | Part[];

    if (imageBase64) {
      const mimeTypeMatch = imageBase64.match(/^data:(image\/\w+);base64,/);
      if (!mimeTypeMatch) throw new Error("Invalid base64 image format");
      const mimeType = mimeTypeMatch[1];
      const pureBase64 = imageBase64.substring(mimeTypeMatch[0].length);

      const imagePart: Part = {
        inlineData: { mimeType, data: pureBase64 },
      };
      const textPart: Part = { text: message };
      content = [textPart, imagePart];
    } else {
      content = message;
    }

    const response = await chat.sendMessage({ message: content });
    return response.text || "I didn't get a response. Please try asking again.";
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    if (error instanceof Error) {
        return `I'm sorry, I ran into an issue: ${error.message}. Please try again.`;
    }
    return "I'm sorry, I'm having trouble connecting to the math brain right now.";
  }
}

export function clearChatSession() {
    chat = null;
}

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import ChatWindow from './components/ChatWindow';
import ChatInput from './components/ChatInput';
import RewardNotification from './components/RewardNotification';
import ImageUploadModal from './components/ImageUploadModal';
import { sendMessage, clearChatSession } from './services/geminiService';
import { getBadgeById } from './data/badges';
import type { Message, Badge } from './types';

const STORAGE_KEYS = {
  MESSAGES: 'ixl_assistant_messages',
  POINTS: 'ixl_assistant_points',
  BADGES: 'ixl_assistant_badges'
};

const DEFAULT_WELCOME: Message = {
  role: 'model',
  text: "Hello! I'm Mr. Rankin's Assistant. I'm here to help you understand your math problems. Tell me, which IXL skill are you working on today?",
};

const parseGamificationRewards = (text: string) => {
  let cleanText = text;
  let pointsAwarded = 0;
  let badgeId: string | null = null;

  const pointsRegex = /\[POINTS:(\d+)\]/g;
  let pointsMatch;
  while ((pointsMatch = pointsRegex.exec(text)) !== null) {
    pointsAwarded += parseInt(pointsMatch[1], 10);
  }
  cleanText = cleanText.replace(pointsRegex, '').trim();

  const badgeRegex = /\[BADGE:([\w_]+)\]/g;
  const badgeMatch = badgeRegex.exec(text);
  if (badgeMatch) {
    badgeId = badgeMatch[1];
  }
  cleanText = cleanText.replace(badgeRegex, '').trim();

  return { cleanText, pointsAwarded, badgeId };
};

const App: React.FC = () => {
  // State initialization with loading from localStorage
  const [messages, setMessages] = useState<Message[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.MESSAGES);
    return saved ? JSON.parse(saved) : [DEFAULT_WELCOME];
  });
  const [points, setPoints] = useState<number>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.POINTS);
    return saved ? parseInt(saved, 10) : 0;
  });
  const [earnedBadges, setEarnedBadges] = useState<string[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.BADGES);
    return saved ? JSON.parse(saved) : [];
  });

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [lastReward, setLastReward] = useState<{ points: number; badge: Badge | null }>({ points: 0, badge: null });

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.MESSAGES, JSON.stringify(messages));
  }, [messages]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.POINTS, points.toString());
  }, [points]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.BADGES, JSON.stringify(earnedBadges));
  }, [earnedBadges]);

  const handleSendMessage = async (userInput: string, imageBase64?: string) => {
    if (!userInput.trim() && !imageBase64) return;

    const userMessage: Message = { role: 'user', text: userInput, image: imageBase64 };
    const updatedMessages = [...messages, userMessage];
    setMessages(updatedMessages);
    setIsLoading(true);
    setError(null);
    setLastReward({ points: 0, badge: null });

    try {
      // Prepare history for API if chat isn't initialized
      // We map our messages to the format expected by the SDK
      const history = updatedMessages.slice(0, -1).map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const modelResponseText = await sendMessage(userInput, imageBase64, history);
      const { cleanText, pointsAwarded, badgeId } = parseGamificationRewards(modelResponseText);

      const modelMessage: Message = { role: 'model', text: cleanText };
      setMessages((prevMessages) => [...prevMessages, modelMessage]);

      let newBadge: Badge | null = null;
      if (badgeId && !earnedBadges.includes(badgeId)) {
        setEarnedBadges(prev => [...prev, badgeId]);
        newBadge = getBadgeById(badgeId) || null;
      }

      if (pointsAwarded > 0 || newBadge) {
          setPoints(prev => prev + pointsAwarded);
          setLastReward({ points: pointsAwarded, badge: newBadge });
      }

    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred.';
      setError(errorMessage);
      setMessages((prevMessages) => [...prevMessages, { role: 'model', text: "Oops! Something went wrong. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReview = (messageText: string) => {
    const prompt = `I'd like to review this part: "${messageText}". \n\nCan you explain it again in a different way and give me a practice mini-problem?`;
    handleSendMessage(prompt);
  };

  const handleReset = () => {
    if (window.confirm("Are you sure you want to reset your chat history and points?")) {
        localStorage.removeItem(STORAGE_KEYS.MESSAGES);
        localStorage.removeItem(STORAGE_KEYS.POINTS);
        localStorage.removeItem(STORAGE_KEYS.BADGES);
        setMessages([DEFAULT_WELCOME]);
        setPoints(0);
        setEarnedBadges([]);
        clearChatSession();
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-100 font-sans text-gray-900">
      <Header points={points} badgeCount={earnedBadges.length} onReset={handleReset} />
      <RewardNotification points={lastReward.points} badge={lastReward.badge} />
       <ImageUploadModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSend={(prompt, image) => {
          handleSendMessage(prompt, image);
          setIsModalOpen(false);
        }}
      />
      <main className="flex-1 overflow-hidden">
        <ChatWindow 
          messages={messages} 
          isLoading={isLoading} 
          onReview={handleReview}
        />
      </main>
      <footer className="bg-white border-t border-gray-200 p-2 sm:p-4">
        <ChatInput 
            onSendMessage={(text) => handleSendMessage(text)} 
            isLoading={isLoading}
            onUploadClick={() => setIsModalOpen(true)}
        />
        {error && <p className="text-red-500 text-center text-sm mt-2">{error}</p>}
      </footer>
    </div>
  );
};

export default App;

